import React from 'react'
import {useState, useContext, useRef, useEffect} from 'react'
import styled from 'styled-components'
import { FlexContainer } from '../../../Containers/Flex-container/FlexContainer'
import { MainSelect } from '../../../Components/Main-select/Main-select'
import { ReactComponent as Filter } from '../../../icons/filters.svg'
import { ReactComponent as Chevron } from '../../../icons/chevron-down.svg'
import { Sorting } from './Sorting'
import { FiltersContext } from '../../../App/App'
import { useResize } from '../../../Hooks/useResize'
import { Filters } from './Filters'
import { Aside } from '../../../Components/Aside/Aside'



const StyledWrapper = styled.div`
  position: relative;
  margin:30px 0 0 0;

  @media (max-width:993px) {
    display: flex;
    justify-content: center;
  }


  .show{
        position: absolute;
        top:3%;
        transition: all .5s;
        opacity: 1;
        visibility: visible;
        z-index: 4;
  }
  .hide{
        position: absolute;
        top: -5%;
        transition: all .5s;
        opacity: 0;
        visibility: hidden;
        z-index: -1;
  }

  @media (max-width: 568px) {
    .show{
        overflow-x: hidden;
        z-index:5;
        opacity: 1;
        visibility: visible;
        position: static;
  }
    .hide{
        overflow-x: hidden;
        position: static;
        opacity: 1;
        z-index:0;
        visibility: visible;
    }
  }
  .wrapper-scroll{
    border:2px solid var(--border);
    border-radius:4px;
    margin:10px 0 0 0;
    padding:0 10px;
    height:200px;
    overflow-Y:scroll;

  &::-webkit-scrollbar {
    width:9px;
  }

   &::-webkit-scrollbar-track{
    height:280px;
  } 
  &::-webkit-scrollbar-thumb{
    border-radius: 6px;
    background: var(--gradient, linear-gradient(92deg, #C09E6C -1.94%, #FFEBCC 40.99%, #BF936B 98.79%));
   
  }
  .scroll-item{
    padding: 5px 0 0 0;
    font-size:20px;
    text-align: left;
  } 
}

.all-items{
  margin:20px 0 0px 0;
  font-size:16px;
  text-align: left;
}

`


export const SelectCards:React.FC = () => {
  const [openSorting, setOpenSorting] = useState(false);
  const {filtersOpen, setFiltersOpen} = useContext(FiltersContext);
  const { isScreenMd, isScreenSm } = useResize();

  const wrapRef = useRef<HTMLInputElement>(null)

   
  const handleClosed = (event:any) =>{
      if(wrapRef.current && !wrapRef.current.contains(event.target)){
        setFiltersOpen(!filtersOpen)
      } 
  }

  useEffect(() =>{
      document.addEventListener('mousedown', handleClosed)
  }, [])


  return (
    <StyledWrapper>
      <FlexContainer filtersResponse align='center' ref={wrapRef}>
        <MainSelect responseSelect left={filtersOpen ? '7px': '0'} padding='10px 20px' width={filtersOpen ? '290px' : '305px'} fontSize='18px' onClick={()=> setFiltersOpen(!filtersOpen)}>
          Фильтры
          <Filter/>
        </MainSelect>
        <div className={filtersOpen ? `${'show'}` : `${'hide'}` }>
          {
            

            isScreenMd && isScreenSm ? <Filters/> :
            <Aside>
            sss
            sss
            
            </Aside>
          }
        </div>
        <MainSelect responseSelectPop padding='10px 30px' width='305px' left={filtersOpen ? '35px' : '20px'} fontSize='18px' onClick={() => setOpenSorting(!openSorting)}>
          По популярности
          <Chevron/>
        </MainSelect>
        <div className={openSorting ? `${'show'}` : `${'hide'}` }>
          <Sorting  />
        </div>
      </FlexContainer>
    </StyledWrapper>
  )
}
